	Use:   "add",
	Short: "Add a new photo entry",
	Run: func(cmd *cobra.Command, args []string) {
		date, _ := cmd.Flags().GetString("date")
		category, _ := cmd.Flags().GetString("category")
		description, _ := cmd.Flags().GetString("description")

		photoDir := filepath.Join("photos", category)
		err := os.MkdirAll(photoDir, 0755)
		if err != nil {
			fmt.Println("Error creating category directory:", err)
			return
		}

		photoFile := filepath.Join(photoDir, date+".txt")
		file, err := os.Create(photoFile)
		if err != nil {
			fmt.Println("Error creating photo entry:", err)
			return
		}
		defer file.Close()

		_, err = file.WriteString(fmt.Sprintf("Date: %s\nCategory: %s\nDescription: %s\n", date, category, description))
		if err != nil {
			fmt.Println("Error writing photo metadata:", err)
			return
		}

		fmt.Println("Photo added successfully")
	},
}

