  return from(axios.get(url)).pipe(
    timeout(10000), // 10 seconds timeout
    catchError(error => {
      console.error('Error fetching URL:', error.message);
      return Observable.throw(error);
    })
  );
}

const urlChanges$ = timer(0, pollInterval).pipe(
  switchMap(() => fetchUrlContent(targetUrl)),
  distinctUntilChanged((prev, curr) => JSON.stringify(prev.data) === JSON.stringify(curr.data)),
  catchError(error => {
    console.error('Error in polling:', error.message);
    return Observable.throw(error);
  })
);

urlChanges$.subscribe({
  next: response => console.log('URL content changed:', response.data),
  error: error => console.error('Polling error:', error.message)
