use futures::future::join_all;
use serde::Deserialize;
use std::fs::File;
use std::io::{self, Read, Write};
use std::path::PathBuf;
use tokio::fs;
use tokio::io::AsyncWriteExt;

#[derive(Debug, Deserialize)]
struct FileList {
    files: Vec<PathBuf>,
}

async fn read_file(path: &PathBuf) -> io::Result<String> {
    let mut file = fs::File::open(path).await?;
    let mut contents = String::new();
    file.read_to_string(&mut contents).await?;
    Ok(contents)
}

#[tokio::main]
async fn main() -> io::Result<()> {
    // Read JSON input
    let mut input_file = File::open("input.json")?;
    let mut json_str = String::new();
    input_file.read_to_string(&mut json_str)?;
    let file_list: FileList = serde_json::from_str(&json_str)?;

    // Process files asynchronously
    let futures = file_list.files.iter().map(|path| read_file(path));
    let results = join_all(futures).await;

    // Concatenate contents with error handling
    let mut output = String::new();
    for result in results {
        match result {
            Ok(content) => output.push_str(&content),
            Err(e) => eprintln!("Error reading file: {}", e),
        }
    }

    // Write output file
    let mut output_file = fs::File::create("output.txt").await?;
    output_file.write_all(output.as_bytes()).await?;

    Ok(())
}
