import click
import requests
from urllib.parse import urlparse

@click.command()
@click.option('--file', required=True, help='Path to the file containing URLs.')
def check_urls(file):
    """Read URLs from a file, make GET requests, and print status codes and response lengths."""
    try:
        with open(file, 'r') as f:
            urls = [line.strip() for line in f.readlines() if line.strip()]
    except FileNotFoundError:
        click.echo(f"Error: File '{file}' not found.")
        return

    for url in urls:
        try:
            parsed = urlparse(url)
            if not all([parsed.scheme, parsed.netloc]):
                raise ValueError("Invalid URL")

            response = requests.get(url)
            click.echo(f"URL: {url} | Status: {response.status_code} | Length: {len(response.content)}")
        except requests.exceptions.RequestException as e:
            click.echo(f"Error fetching {url}: {str(e)}")
        except ValueError as e:
            click.echo(f"Invalid URL: {url}")

if __name__ == '__main__':
    check_urls()
