use tide::prelude::*;
use tide::Request;

#[derive(Debug, Deserialize)]
struct ProductRequest {
    codes: Vec<String>,
}

#[derive(Debug, Serialize)]
struct ProductResponse {
    valid: Vec<String>,
    invalid: Vec<String>,
}

#[async_std::main]
async fn main() -> tide::Result<()> {
    let mut app = tide::new();

    // Predefined list of valid product codes
    let valid_codes = vec![
        "ABC123".to_string(),
        "DEF456".to_string(),
        "GHI789".to_string(),
    ];

    app.at("/validate").post(|mut req: Request<()>| async move {
        let body: ProductRequest = match req.body_json().await {
            Ok(b) => b,
            Err(_) => {
                return Ok(tide::Response::builder(tide::StatusCode::BadRequest)
                    .body("Malformed JSON")
                    .build());
            }
        };

        let mut response = ProductResponse {
            valid: Vec::new(),
            invalid: Vec::new(),
        };

        for code in body.codes {
            if valid_codes.contains(&code) {
                response.valid.push(code);
            } else {
                response.invalid.push(code);
            }
        }

        Ok(tide::Response::builder(tide::StatusCode::Ok)
            .body_json(&response)?)
    });

    app.listen("127.0.0.1:8080").await?;
    Ok(())
}
