use hyper::service::{make_service_fn, service_fn};
use hyper::{Body, Method, Request, Response, Server, StatusCode};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::fs::File;
use std::io::Read;
use std::sync::Arc;

#[derive(Serialize, Deserialize, Debug)]
struct Employee {
    id: u32,
    name: String,
    position: String,
    department: String,
}

async fn handle_request(req: Request<Body>, data: Arc<HashMap<u32, Employee>>) -> Result<Response<Body>, hyper::Error> {
    match (req.method(), req.uri().path()) {
        (&Method::GET, "/employees") => {
            let employees: Vec<&Employee> = data.values().collect();
            let response = match serde_json::to_string(&employees) {
                Ok(json) => Response::new(Body::from(json)),
                Err(_) => Response::builder()
                    .status(StatusCode::INTERNAL_SERVER_ERROR)
                    .body(Body::from("Failed to serialize response"))
                    .unwrap(),
            };
            Ok(response)
        }
        (&Method::GET, path) if path.starts_with("/employees/") => {
            let id = path.trim_start_matches("/employees/").parse::<u32>().ok();
            if let Some(id) = id {
                if let Some(employee) = data.get(&id) {
                    let response = match serde_json::to_string(employee) {
                        Ok(json) => Response::new(Body::from(json)),
                        Err(_) => Response::builder()
                            .status(StatusCode::INTERNAL_SERVER_ERROR)
                            .body(Body::from("Failed to serialize response"))
                            .unwrap(),
                    };
                    Ok(response)
                } else {
                    Ok(Response::builder()
                        .status(StatusCode::NOT_FOUND)
                        .body(Body::from("Employee not found"))
                        .unwrap())
                }
            } else {
                Ok(Response::builder()
                    .status(StatusCode::BAD_REQUEST)
                    .body(Body::from("Invalid employee ID"))
                    .unwrap())
            }
        }
        _ => {
            Ok(Response::builder()
                .status(StatusCode::NOT_FOUND)
                .body(Body::from("Endpoint not found"))
                .unwrap())
        }
    }
}

#[tokio::main]
async fn main() {
    let file = match File::open("employees.json") {
        Ok(file) => file,
        Err(_) => {
            eprintln!("Failed to open employees.json");
            return;
        }
    };

    let mut contents = String::new();
    if let Err(_) = file.take(1024 * 1024).read_to_string(&mut contents) {
        eprintln!("Failed to read employees.json");
        return;
    }

    let employees: Vec<Employee> = match serde_json::from_str(&contents) {
        Ok(employees) => employees,
        Err(_) => {
            eprintln!("Failed to parse employees.json");
            return;
        }
    };

    let data: HashMap<u32, Employee> = employees.into_iter().map(|e| (e.id, e)).collect();
    let data = Arc::new(data);

    let make_svc = make_service_fn(move |_conn| {
        let data = Arc::clone(&data);
        async move {
            Ok::<_, hyper::Error>(service_fn(move |req| handle_request(req, Arc::clone(&data))))
        }
    });

    let addr = ([127, 0, 0, 1], 3000).into();
    let server = Server::bind(&addr).serve(make_svc);

    println!("Server running at http://{}", addr);

    if let Err(e) = server.await {
        eprintln!("server error: {}", e);
    }
}
