use tokio::net::TcpListener;
use tokio::io::{AsyncReadExt, AsyncWriteExt};
use serde::{Deserialize, Serialize};
use std::error::Error;

#[derive(Debug, Deserialize, Serialize)]
struct RequestData {
    integers: Vec<i32>,
}

async fn handle_client(mut stream: tokio::net::TcpStream) -> Result<(), Box<dyn Error>> {
    let mut buffer = Vec::new();
    let mut temp_buffer = [0; 1024];

    loop {
        let bytes_read = stream.read(&mut temp_buffer).await?;
        if bytes_read == 0 {
            break;
        }
        buffer.extend_from_slice(&temp_buffer[..bytes_read]);
    }

    let request_data: RequestData = match serde_json::from_slice(&buffer) {
        Ok(data) => data,
        Err(e) => {
            let error_response = format!("Invalid JSON format: {}", e);
            stream.write_all(error_response.as_bytes()).await?;
            return Ok(());
        }
    };

    let mut sorted_integers = request_data.integers.clone();
    tokio::task::spawn_blocking(move || {
        sorted_integers.sort();
        sorted_integers
    }).await?;

    let response = serde_json::to_string(&sorted_integers)?;
    stream.write_all(response.as_bytes()).await?;

    Ok(())
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn Error>> {
    let listener = TcpListener::bind("127.0.0.1:8080").await?;

    loop {
        let (stream, _) = listener.accept().await?;
        tokio::spawn(async move {
            if let Err(e) = handle_client(stream).await {
                eprintln!("Error handling client: {}", e);
            }
        });
    }
}
