import * as fs from 'fs';
import * as E from 'fp-ts/Either';
import * as TE from 'fp-ts/TaskEither';
import * as T from 'fp-ts/Task';
import * as O from 'fp-ts/Option';
import { pipe } from 'fp-ts/function';
import * as t from 'io-ts';

// Define the UserSettings type
const UserSettings = t.type({
  theme: t.string,
  notificationsEnabled: t.boolean,
  fontSize: t.number,
});

type UserSettings = t.TypeOf<typeof UserSettings>;

// Path to the JSON file
const SETTINGS_FILE_PATH = './userSettings.json';

// Read user settings from file
const readSettings = (): TE.TaskEither<Error, UserSettings> => {
  return TE.tryCatch(
    () => fs.promises.readFile(SETTINGS_FILE_PATH, 'utf-8').then(JSON.parse),
    (error) => new Error(`Failed to read settings: ${error}`)
  );
};

// Validate settings using Either
const validateSettings = (data: unknown): E.Either<Error, UserSettings> => {
  return pipe(
    UserSettings.decode(data),
    E.mapLeft((errors) => new Error(`Invalid settings: ${errors}`))
  );
};

// Update settings (immutable)
const updateSettings = (
  current: UserSettings,
  updates: Partial<UserSettings>
): UserSettings => {
  return { ...current, ...updates };
};

// Write settings back to file
const writeSettings = (settings: UserSettings): TE.TaskEither<Error, void> => {
  return TE.tryCatch(
    () => fs.promises.writeFile(SETTINGS_FILE_PATH, JSON.stringify(settings, null, 2)),
    (error) => new Error(`Failed to write settings: ${error}`)
  );
};

// Main service function to handle settings update
const updateUserSettings = (
  updates: Partial<UserSettings>
): TE.TaskEither<Error, UserSettings> => {
  return pipe(
    readSettings(),
    TE.chain((data) => TE.fromEither(validateSettings(data))),
    TE.map((settings) => updateSettings(settings, updates)),
    TE.chainFirst((newSettings) => writeSettings(newSettings))
  );
};

