import * as t from 'io-ts';
import { either } from 'fp-ts/lib/Either';
import { pipe } from 'fp-ts/lib/function';
import * as E from 'fp-ts/lib/Either';
import axios from 'axios';

// Custom date codec for publishedDate
const DateFromString = new t.Type<Date, string, unknown>(
  'DateFromString',
  (u): u is Date => u instanceof Date,
  (u, c) =>
    pipe(
      t.string.validate(u, c),
      either.chain((s) => {
        const d = new Date(s);
        return isNaN(d.getTime()) ? t.failure(u, c) : t.success(d);
      })
    ),
  (a) => a.toISOString()
);

// BlogPost codec
const BlogPost = t.type({
  id: t.string,
  title: t.string,
  content: t.string,
  publishedDate: DateFromString,
});

const BlogPosts = t.array(BlogPost);

type BlogPost = t.TypeOf<typeof BlogPost>;

async function fetchAndValidateBlogPosts(apiEndpoint: string): Promise<void> {
  try {
    const response = await axios.get(apiEndpoint);
    const validationResult = BlogPosts.decode(response.data);

    if (E.isLeft(validationResult)) {
      console.error('Validation failed:', validationResult.left);
      return;
    }

    const blogPosts = validationResult.right;
    blogPosts.forEach((post) => {
      console.log(`Title: ${post.title}`);
      console.log(`Content: ${post.content}\n`);
    });
  } catch (error) {
    if (axios.isAxiosError(error)) {
      console.error('API request failed:', error.message);
    } else {
      console.error('An unexpected error occurred:', error);
    }
  }
}

