        books {
            id -> Integer,
            title -> Text,
            author -> Text,
            year_published -> Integer,
            quantity_in_stock -> Integer,
        }
    }
}

#[derive(Queryable, Insertable, Debug)]
#[table_name = "books"]
struct Book {
    id: i32,
    title: String,
    author: String,
    year_published: i32,
    quantity_in_stock: i32,
}

fn establish_connection() -> PgConnection {
    let database_url = env::var("DATABASE_URL")
        .expect("DATABASE_URL must be set");
    PgConnection::establish(&database_url)
        .expect(&format!("Error connecting to {}", database_url))
}

fn add_book(conn: &PgConnection, title: &str, author: &str, year_published: i32, quantity: i32) -> Result<(), Error> {
    use schema::books::dsl::*;

    let new_book = Book {
        id: 0,
        title: title.to_string(),
        author: author.to_string(),
        year_published,
        quantity_in_stock: quantity,
    };

    diesel::insert_into(books)
        .values(&new_book)
        .execute(conn)?;

    Ok(())
}

fn update_book(conn: &PgConnection, book_id: i32, new_title: Option<&str>, new_author: Option<&str>, 
               new_year: Option<i32>, new_quantity: Option<i32>) -> Result<(), Error> {
    use schema::books::dsl::*;

    if let Some(title) = new_title {
        diesel::update(books.find(book_id))
            .set(title.eq(title))
            .execute(conn)?;
    }

    if let Some(auth) = new_author {
        diesel::update(books.find(book_id))
            .set(author.eq(auth))
            .execute(conn)?;
    }

    if let Some(yr) = new_year {
        diesel::update(books.find(book_id))
            .set(year_published.eq(yr))
            .execute(conn)?;
    }

    if let Some(qty) = new_quantity {
        diesel::update(books.find(book_id))
            .set(quantity_in_stock.eq(qty))
            .execute(conn)?;
    }

    Ok(())
}

fn find_books_by_title(conn: &PgConnection, search_title: &str) -> Result<Vec<Book>, Error> {
    use schema::books::dsl::*;

    books.filter(title.like(format!("%{}%", search_title)))
        .load::<Book>(conn)
}

fn find_books_by_author(conn: &PgConnection, search_author: &str) -> Result<Vec<Book>, Error> {
    use schema::books::dsl::*;

    books.filter(author.like(format!("%{}%", search_author)))
        .load::<Book>(conn)
}

fn delete_book(conn: &PgConnection, book_id: i32) -> Result<(), Error> {
    use schema::books::dsl::*;

    diesel::delete(books.find(book_id))
        .execute(conn)?;

    Ok(())
}

