use async_std::{
    io::{self, BufReader},
    net::{TcpListener, TcpStream},
    prelude::*,
    task,
};

async fn handle_client(mut stream: TcpStream) -> io::Result<()> {
    let peer_addr = stream.peer_addr()?;
    println!("New client connected: {}", peer_addr);

    // Send greeting
    stream.write_all(b"Welcome to the echo server!\n").await?;

    let mut reader = BufReader::new(stream.clone());
    let mut line = String::new();

    loop {
        line.clear();
        match reader.read_line(&mut line).await {
            Ok(0) => {
                println!("Client {} disconnected", peer_addr);
                break;
            }
            Ok(_) => {
                let response = format!("Received: {}", line);
                if let Err(e) = stream.write_all(response.as_bytes()).await {
                    eprintln!("Failed to send to client {}: {}", peer_addr, e);
                    break;
                }
            }
            Err(e) => {
                eprintln!("Error reading from client {}: {}", peer_addr, e);
                break;
            }
        }
    }

    Ok(())
}

#[async_std::main]
async fn main() -> io::Result<()> {
    let listener = TcpListener::bind("127.0.0.1:8080").await?;
    println!("Server listening on 127.0.0.1:8080");

    let mut incoming = listener.incoming();

    while let Some(stream) = incoming.next().await {
        match stream {
            Ok(stream) => {
                task::spawn(async move {
                    if let Err(e) = handle_client(stream).await {
                        eprintln!("Error handling client: {}", e);
                    }
                });
            }
            Err(e) => {
                eprintln!("Connection failed: {}", e);
            }
        }
    }

    Ok(())
}
