package main

import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"log"
	"os"
	"path/filepath"
	"sort"
	"time"

	"github.com/urfave/cli/v2"
)

type Record struct {
	Name      string    `json:"name"`
	Timestamp time.Time `json:"timestamp"`
}

func main() {
	app := &cli.App{
		Name:  "json-processor",
		Usage: "Process JSON files in a directory",
		Flags: []cli.Flag{
			&cli.StringFlag{
				Name:     "dir",
				Aliases:  []string{"d"},
				Usage:    "Directory containing JSON files",
				Required: true,
			},
			&cli.StringFlag{
				Name:    "time",
				Aliases: []string{"t"},
				Usage:   "Filter records after this time (RFC3339 format)",
			},
		},
		Action: func(c *cli.Context) error {
			dirPath := c.String("dir")
			timeFilterStr := c.String("time")

			var timeFilter time.Time
			if timeFilterStr != "" {
				var err error
				timeFilter, err = time.Parse(time.RFC3339, timeFilterStr)
				if err != nil {
					return fmt.Errorf("invalid time format: %v", err)
				}
			}

			files, err := ioutil.ReadDir(dirPath)
			if err != nil {
				return fmt.Errorf("failed to read directory: %v", err)
			}

			var allNames []string

			for _, file := range files {
				if filepath.Ext(file.Name()) != ".json" {
					continue
				}

				filePath := filepath.Join(dirPath, file.Name())
				data, err := ioutil.ReadFile(filePath)
				if err != nil {
					return fmt.Errorf("failed to read file %s: %v", file.Name(), err)
				}

				var records []Record
				if err := json.Unmarshal(data, &records); err != nil {
					return fmt.Errorf("failed to parse JSON in file %s: %v", file.Name(), err)
				}

				for _, record := range records {
					if timeFilterStr == "" || record.Timestamp.After(timeFilter) {
						allNames = append(allNames, record.Name)
					}
				}
			}

			sort.Strings(allNames)

			for _, name := range allNames {
				fmt.Println(name)
			}

			return nil
		},
	}

	if err := app.Run(os.Args); err != nil {
		log.Fatal(err)
	}
}
