  public async updateAuthor(@Path() id: string, @Body() requestBody: Author): Promise<Author> {
    try {
      const updatedAuthor = await new AuthorsService().update(id, requestBody);
      if (!updatedAuthor) {
        this.setStatus(404);
        throw new Error('Author not found');
      }
      return updatedAuthor;
    } catch (error) {
      this.setStatus(400);
      throw new Error('Invalid author data');
    }
  }

  @Delete('{id}')
  public async deleteAuthor(@Path() id: string): Promise<void> {
    const success = await new AuthorsService().delete(id);
    if (!success) {
      this.setStatus(404);
      throw new Error('Author not found');
    }
    this.setStatus(204);
  }
}

