import { Book } from '../models/Book';

export class BooksService {
  private books: Book[] = [];

  public async get(isbn: string): Promise<Book | undefined> {
    return this.books.find(book => book.isbn === isbn);
  }

  public async create(book: Book): Promise<Book> {
    this.books.push(book);
    return book;
  }

  public async update(isbn: string, book: Book): Promise<Book | undefined> {
    const index = this.books.findIndex(b => b.isbn === isbn);
    if (index !== -1) {
      this.books[index] = book;
      return book;
    }
    return undefined;
  }

  public async delete(isbn: string): Promise<boolean> {
    const initialLength = this.books.length;
    this.books = this.books.filter(book => book.isbn !== isbn);
    return this.books.length !== initialLength;
  }
}

