package main

import (
	"fmt"
	"log"
	"os"
	"syscall"
	"time"

	"github.com/go-co-op/gocron"
)

func checkDiskUsage() (float64, error) {
	var stat syscall.Statfs_t
	err := syscall.Statfs("/", &stat)
	if err != nil {
		return 0, err
	}

	total := stat.Blocks * uint64(stat.Bsize)
	free := stat.Bfree * uint64(stat.Bsize)
	used := total - free
	usagePercent := (float64(used) / float64(total)) * 100

	return usagePercent, nil
}

func logDiskUsage() {
	usage, err := checkDiskUsage()
	if err != nil {
		log.Printf("Error checking disk usage: %v\n", err)
		return
	}

	logEntry := fmt.Sprintf("[%s] Disk usage: %.2f%%\n", time.Now().Format(time.RFC3339), usage)

	file, err := os.OpenFile("disk_usage.log", os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
	if err != nil {
		log.Printf("Error opening log file: %v\n", err)
		return
	}
	defer file.Close()

	if _, err := file.WriteString(logEntry); err != nil {
		log.Printf("Error writing to log file: %v\n", err)
		return
	}
}

func main() {
	s := gocron.NewScheduler(time.UTC)

	_, err := s.Every(10).Minutes().Do(logDiskUsage)
	if err != nil {
		log.Fatalf("Error scheduling task: %v\n", err)
	}

	s.StartBlocking()
}
