use serde::{Deserialize, Serialize};
use std::fs::File;
use std::io::prelude::*;
use std::error::Error;

#[derive(Debug, Serialize, Deserialize)]
struct Student {
    name: String,
    age: u32,
    gpa: f32,
}

#[derive(Debug, Serialize)]
struct AverageGPA {
    average_gpa: f32,
}

fn main() -> Result<(), Box<dyn Error>> {
    // Read the JSON file
    let mut file = File::open("students.json")?;
    let mut contents = String::new();
    file.read_to_string(&mut contents)?;

    // Deserialize the JSON into a list of Student structs
    let students: Vec<Student> = serde_json::from_str(&contents)?;

    // Calculate the average GPA
    let total_gpa: f32 = students.iter().map(|s| s.gpa).sum();
    let average_gpa = total_gpa / students.len() as f32;

    // Serialize the result back into JSON
    let result = AverageGPA { average_gpa };
    let result_json = serde_json::to_string_pretty(&result)?;

    // Write the result to a new JSON file
    let mut output_file = File::create("average_gpa.json")?;
    output_file.write_all(result_json.as_bytes())?;

    Ok(())
}
