```rust
use axum::{
    extract::Extension,
    http::StatusCode,
    response::IntoResponse,
    routing::{get, post},
    Json, Router,
};
use serde::{Deserialize, Serialize};
use sqlx::postgres::PgPoolOptions;
use sqlx::{Pool, Postgres};
use std::net::SocketAddr;
use bcrypt::{hash, verify, DEFAULT_COST};

#[derive(Debug, Serialize, Deserialize)]
struct User {
    username: String,
    password: String,
}

#[derive(Debug, Serialize, Deserialize)]
struct RegisterResponse {
    message: String,
}

#[derive(Debug, Serialize, Deserialize)]
struct LoginResponse {
    message: String,
    token: Option<String>,
}

#[derive(Debug)]
enum AuthError {
    DatabaseError(sqlx::Error),
    HashingError(bcrypt::BcryptError),
    InvalidCredentials,
}

impl IntoResponse for AuthError {
    fn into_response(self) -> axum::response::Response {
        let (status, message) = match self {
            AuthError::DatabaseError(_) => (StatusCode::INTERNAL_SERVER_ERROR, "Database error"),
            AuthError::HashingError(_) => (StatusCode::INTERNAL_SERVER_ERROR, "Hashing error"),
            AuthError::InvalidCredentials => (StatusCode::UNAUTHORIZED, "Invalid credentials"),
        };
        (status, message).into_response()
    }
}

async fn register(
    Extension(pool): Extension<Pool<Postgres>>,
    Json(user): Json<User>,
) -> Result<Json<RegisterResponse>, AuthError> {
    let hashed_password = hash(user.password, DEFAULT_COST).map_err(AuthError::HashingError)?;

    sqlx::query!(
        r#"
        INSERT INTO users (username, password)
        VALUES ($1, $2)
        "#,
        user.username,
        hashed_password
    )
    .execute(&pool)
    .await
    .map_err(AuthError::DatabaseError)?;

    Ok(Json(RegisterResponse {
        message: "User registered successfully".to_string(),
    }))
}

async fn login(
    Extension(pool): Extension<Pool<Postgres>>,
    Json(user): Json<User>,
) -> Result<Json<LoginResponse>, AuthError> {
    let db_user = sqlx::query!(
        r#"
        SELECT password FROM users WHERE username = $1
        "#,
        user.username
    )
    .fetch_one(&pool)
    .await
    .map_err(|_| AuthError::InvalidCredentials)?;

    let is_valid = verify(user.password, &db_user.password).map_err(AuthError::HashingError)?;

    if !is_valid {
        return Err(AuthError::InvalidCredentials);
    }

    Ok(Json(LoginResponse {
        message: "Login successful".to_string(),
        token: Some("sample_token".to_string()),
    }))
}

#[tokio::main]
async fn main() -> Result<(), sqlx::Error> {
    let pool = PgPoolOptions::new()
        .max_connections(5)
        .connect("postgres://username:password@localhost/database")
        .await?;

    sqlx::migrate!().run(&pool).await?;

    let app = Router::new()
        .route("/register", post(register))
        .route("/login", post(login))
        .layer(Extension(pool));

    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));
    axum::Server::bind(&addr)
        .serve(app.into_make_service())
        .await
        .unwrap();

    Ok(())
}
