async def fetch_headlines(session, url, name):
    try:
        async with session.get(url) as response:
            if response.status == 200:
                data = await response.json()
                # Adjust parsing logic based on the API's response structure
                headlines = data.get('articles', [])
                extracted = []
                for article in headlines:
                    extracted.append({
                        'source': name,
                        'headline': article.get('title', ''),
                        'timestamp': datetime.strptime(
                            article.get('publishedAt', '1970-01-01T00:00:00Z'),
                            '%Y-%m-%dT%H:%M:%SZ'
                        )
                    })
                return extracted
            else:
                print(f"Error fetching {name}: HTTP {response.status}")
                return []
    except (aiohttp.ClientError, ValueError, KeyError) as e:
        print(f"Error processing {name}: {str(e)}")
        return []

