        .catch(error => {
          fs.unlinkSync(filePath);
          res.status(500).json({ error: 'Failed to upload products', details: error.message });
        });
    })
    .on('error', (error) => {
      fs.unlinkSync(filePath);
      res.status(500).json({ error: 'Error parsing CSV file', details: error.message });
