package main

import (
	"fmt"
	"log"
	"os"

	"github.com/gin-gonic/gin"
	"gorm.io/driver/postgres"
	"gorm.io/gorm"
	"gorm.io/gorm/logger"
)

type Book struct {
	gorm.Model
	Title    string `gorm:"not null"`
	Author   string `gorm:"not null"`
	ISBN     string `gorm:"unique;not null"`
	Quantity int    `gorm:"not null"`
}

var db *gorm.DB

func initDB() {
	dsn := fmt.Sprintf("host=%s user=%s password=%s dbname=%s port=%s sslmode=disable",
		os.Getenv("DB_HOST"),
		os.Getenv("DB_USER"),
		os.Getenv("DB_PASSWORD"),
		os.Getenv("DB_NAME"),
		os.Getenv("DB_PORT"),
	)

	var err error
	db, err = gorm.Open(postgres.Open(dsn), &gorm.Config{
		Logger: logger.Default.LogMode(logger.Info),
	})
	if err != nil {
		log.Fatal("Failed to connect to database:", err)
	}

	db.AutoMigrate(&Book{})
}

func addBook(title, author, isbn string, quantity int) error {
	book := Book{
		Title:    title,
		Author:   author,
		ISBN:     isbn,
		Quantity: quantity,
	}
	result := db.Create(&book)
	if result.Error != nil {
		return result.Error
	}
	log.Printf("Added book: %+v", book)
	return nil
}

func updateBook(id uint, title, author, isbn string, quantity int) error {
	var book Book
	result := db.First(&book, id)
	if result.Error != nil {
		return result.Error
	}

	book.Title = title
	book.Author = author
	book.ISBN = isbn
	book.Quantity = quantity

	result = db.Save(&book)
	if result.Error != nil {
		return result.Error
	}
	log.Printf("Updated book: %+v", book)
	return nil
}

func deleteBook(id uint) error {
	var book Book
	result := db.Delete(&book, id)
	if result.Error != nil {
		return result.Error
	}
	log.Printf("Deleted book with ID: %d", id)
	return nil
}

func getBook(id uint) (Book, error) {
	var book Book
	result := db.First(&book, id)
	if result.Error != nil {
		return Book{}, result.Error
	}
	log.Printf("Fetched book: %+v", book)
	return book, nil
}

func getAllBooks() ([]Book, error) {
	var books []Book
	result := db.Find(&books)
	if result.Error != nil {
		return nil, result.Error
	}
	log.Printf("Fetched %d books", len(books))
	return books, nil
}

func main() {
	initDB()

	r := gin.Default()

	r.POST("/books", func(c *gin.Context) {
		var book Book
		if err := c.ShouldBindJSON(&book); err != nil {
			c.JSON(400, gin.H{"error": err.Error()})
			return
		}
		if err := addBook(book.Title, book.Author, book.ISBN, book.Quantity); err != nil {
			c.JSON(500, gin.H{"error": err.Error()})
			return
		}
		c.JSON(200, gin.H{"message": "Book added successfully"})
	})

	r.PUT("/books/:id", func(c *gin.Context) {
		id := c.Param("id")
		var book Book
		if err := c.ShouldBindJSON(&book); err != nil {
			c.JSON(400, gin.H{"error": err.Error()})
			return
		}
		if err := updateBook(book.ID, book.Title, book.Author, book.ISBN, book.Quantity); err != nil {
			c.JSON(500, gin.H{"error": err.Error()})
			return
		}
		c.JSON(200, gin.H{"message": "Book updated successfully"})
	})

	r.DELETE("/books/:id", func(c *gin.Context) {
		id := c.Param("id")
		if err := deleteBook(id); err != nil {
			c.JSON(500, gin.H{"error": err.Error()})
			return
		}
		c.JSON(200, gin.H{"message": "Book deleted successfully"})
	})

	r.GET("/books/:id", func(c *gin.Context) {
		id := c.Param("id")
		book, err := getBook(id)
		if err != nil {
			c.JSON(500, gin.H{"error": err.Error()})
			return
		}
		c.JSON(200, book)
	})

	r.GET("/books", func(c *gin.Context) {
		books, err := getAllBooks()
		if err != nil {
			c.JSON(500, gin.H{"error": err.Error()})
			return
		}
		c.JSON(200, books)
	})

	r.Run()
}
