```go
package main

import (
	"encoding/csv"
	"fmt"
	"os"
	"strconv"
	"sync"

	"github.com/AsynkronIT/protoactor-go/actor"
)

// TradeData represents a single trade entry
type TradeData struct {
	StockSymbol string
	Price       float64
	Volume      int
	FirmID      string
}

// TradingFirmActor is responsible for processing trade data for a specific firm
type TradingFirmActor struct {
	FirmID         string
	TotalVolume    int
	HighestPrice   float64
	StockSymbolMap map[string]struct {
		Volume    int
		MaxPrice  float64
	}
}

// ProcessTrade is the message sent to TradingFirmActor
type ProcessTrade struct {
	Trade TradeData
}

// AggregatorActor collects results from all firm actors
type AggregatorActor struct {
	TotalVolume    int
	HighestPrice   float64
	FirmResponses  map[string]struct {
		Volume    int
		MaxPrice  float64
	}
	ResponseCount int
	TotalFirms    int
	wg            *sync.WaitGroup
}

// TradeResult is the message sent back from TradingFirmActor to AggregatorActor
type TradeResult struct {
	FirmID       string
	TotalVolume  int
	HighestPrice float64
}

// Receive method for TradingFirmActor
func (state *TradingFirmActor) Receive(ctx actor.Context) {
	switch msg := ctx.Message().(type) {
	case *ProcessTrade:
		state.TotalVolume += msg.Trade.Volume
		if msg.Trade.Price > state.HighestPrice {
			state.HighestPrice = msg.Trade.Price
		}

		// Update per-stock statistics
		stockData := state.StockSymbolMap[msg.Trade.StockSymbol]
		stockData.Volume += msg.Trade.Volume
		if msg.Trade.Price > stockData.MaxPrice {
			stockData.MaxPrice = msg.Trade.Price
		}
		state.StockSymbolMap[msg.Trade.StockSymbol] = stockData

		// Send result back to aggregator
		ctx.Send(ctx.Sender(), &TradeResult{
			FirmID:       state.FirmID,
			TotalVolume:  state.TotalVolume,
			HighestPrice: state.HighestPrice,
		})
	}
}

// Receive method for AggregatorActor
func (state *AggregatorActor) Receive(ctx actor.Context) {
	switch msg := ctx.Message().(type) {
	case *TradeResult:
		state.FirmResponses[msg.FirmID] = struct {
			Volume    int
			MaxPrice  float64
		}{
			Volume:    msg.TotalVolume,
			MaxPrice:  msg.HighestPrice,
		}

		state.TotalVolume += msg.TotalVolume
		if msg.HighestPrice > state.HighestPrice {
			state.HighestPrice = msg.HighestPrice
		}

		state.ResponseCount++
		if state.ResponseCount == state.TotalFirms {
			state.wg.Done()
		}
	}
}

func main() {
	// Read CSV file
	file, err := os.Open("trades.csv")
	if err != nil {
		fmt.Printf("Error opening file: %v\n", err)
		return
	}
	defer file.Close()

	reader := csv.NewReader(file)
	records, err := reader.ReadAll()
	if err != nil {
		fmt.Printf("Error reading CSV: %v\n", err)
		return
	}

	// Parse CSV data
	var trades []TradeData
	for _, record := range records {
		if len(record) != 4 {
			fmt.Printf("Invalid record: %v\n", record)
			continue
		}

		price, err := strconv.ParseFloat(record[1], 64)
		if err != nil {
			fmt.Printf("Invalid price: %v\n", record[1])
			continue
		}

		volume, err := strconv.Atoi(record[2])
		if err != nil {
			fmt.Printf("Invalid volume: %v\n", record[2])
			continue
		}

		trades = append(trades, TradeData{
			StockSymbol: record[0],
			Price:       price,
			Volume:      volume,
			FirmID:      record[3],
		})
	}

	// Create actor system
	system := actor.NewActorSystem()

	// Create firm actors
	firmActors := make(map[string]*actor.PID)
	firmIDs := make(map[string]bool)

	for _, trade := range trades {
		if _, exists := firmIDs[trade.FirmID]; !exists {
			firmIDs[trade.FirmID] = true
			props := actor.PropsFromProducer(func() actor.Actor {
				return &TradingFirmActor{
					FirmID:         trade.FirmID,
					StockSymbolMap: make(map[string]struct {
						Volume    int
						MaxPrice  float64
					}),
				}
			})
			firmActors[trade.FirmID] = system.Root.Spawn(props)
		}
	}

	// Create aggregator actor
	var wg sync.WaitGroup
	wg.Add(1)

	aggregatorProps := actor.PropsFromProducer(func() actor.Actor {
		return &AggregatorActor{
			FirmResponses: make(map[string]struct {
				Volume    int
				MaxPrice  float64
			}),
			TotalFirms: len(firmActors),
			wg:         &wg,
		}
	})
	aggregator := system.Root.Spawn(aggregatorProps)

	// Process trades
	for _, trade := range trades {
		if pid, exists := firmActors[trade.FirmID]; exists {
			system.Root.Send(pid, &ProcessTrade{Trade: trade})
		}
	}

	// Wait for all responses
	wg.Wait()

	// Get final results from aggregator
	aggregatorResult, err := system.Root.RequestFuture(aggregator, &actor.FutureMessage{}, -1).Result()
	if err != nil {
		fmt.Printf("Error getting aggregator result: %v\n", err)
		return
	}

	if result, ok := aggregatorResult.(*AggregatorActor); ok {
		fmt.Printf("Total Trading Volume: %d\n", result.TotalVolume)
		fmt.Printf("Highest Price Traded: %.2f\n", result.HighestPrice)
	}
}
