import axios from 'axios';
import { match, P } from 'ts-pattern';

interface Character {
  name: string;
  gender: string;
  species: string[];
}

interface ApiError {
  message: string;
}

const SWAPI_BASE_URL = 'https://swapi.dev/api/people/';

const fetchCharacter = async (id: number): Promise<Character | ApiError> => {
  try {
    const response = await axios.get(`${SWAPI_BASE_URL}${id}/`);
    return response.data;
  } catch (error) {
    return { message: 'Failed to fetch character data' };
  }
};

const formatCharacter = (data: unknown): string => {
  return match(data)
    .with(
      {
        name: P.string,
        gender: P.string,
        species: P.array(P.string),
      },
      (char) => `Name: ${char.name}, Gender: ${char.gender}, Species: ${char.species.join(', ')}`
    )
    .with(
      { message: P.string },
      (err) => `Error: ${err.message}`
    )
    .otherwise(() => 'Unknown data format');
};

const printCharacterData = async (id: number): Promise<void> => {
  const data = await fetchCharacter(id);
  console.log(formatCharacter(data));
};

// Example usage
printCharacterData(1);
