package main

import (
	"sync"
)

func ConcurrentSum[T ~int | ~float64](numbers []T) T {
	var wg sync.WaitGroup
	var sum T
	chunkSize := len(numbers) / 4

	wg.Add(4)
	for i := 0; i < 4; i++ {
		go func(i int) {
			defer wg.Done()
			start := i * chunkSize
			end := start + chunkSize
			if i == 3 {
				end = len(numbers)
			}

			var localSum T
			for _, num := range numbers[start:end] {
				localSum += num
			}

			var mu sync.Mutex
			mu.Lock()
			sum += localSum
			mu.Unlock()
		}(i)
	}

	wg.Wait()
	return sum
}
