```python
import requests
import json
import logging
import sys
import time
from typing import Optional, Dict, Any

# Configure logging
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(levelname)s - %(message)s',
    handlers=[logging.StreamHandler()]
)
logger = logging.getLogger(__name__)

class WeatherAPIClient:
    def __init__(self, api_endpoint: str, api_key: Optional[str] = None, max_retries: int = 3, retry_delay: int = 2):
        self.api_endpoint = api_endpoint
        self.api_key = api_key
        self.max_retries = max_retries
        self.retry_delay = retry_delay
        self.session = requests.Session()
        logger.info(f"Initialized WeatherAPIClient with Python {sys.version_info.major}.{sys.version_info.minor}")

    def _make_request(self, params: Optional[Dict[str, Any]] = None) -> Optional[Dict[str, Any]]:
        headers = {"Accept": "application/json"}
        if self.api_key:
            headers["Authorization"] = f"Bearer {self.api_key}"

        for attempt in range(self.max_retries):
            try:
                response = self.session.get(
                    self.api_endpoint,
                    headers=headers,
                    params=params,
                    timeout=10
                )
                response.raise_for_status()
                return response.json()
            except requests.exceptions.RequestException as e:
                logger.warning(f"Attempt {attempt + 1} failed: {str(e)}")
                if attempt < self.max_retries - 1:
                    time.sleep(self.retry_delay)
                else:
                    logger.error(f"Max retries reached. Failed to fetch weather data: {str(e)}")
                    return None

    def get_weather_data(self, location: Optional[str] = None) -> Optional[Dict[str, Any]]:
        params = {"location": location} if location else None
        weather_data = self._make_request(params)

        if not weather_data:
            return None

        try:
            extracted_data = {
                "temperature": weather_data.get("main", {}).get("temp"),
                "humidity": weather_data.get("main", {}).get("humidity"),
                "conditions": weather_data.get("weather", [{}])[0].get("description")
            }
            return extracted_data
        except (KeyError, IndexError, AttributeError) as e:
            logger.error(f"Error parsing weather data: {str(e)}")
            return None

    def format_weather_output(self, weather_data: Dict[str, Any]) -> str:
        if not weather_data:
            return "No weather data available."

        return (
            f"Weather Conditions:\n"
            f"  Temperature: {weather_data.get('temperature', 'N/A')}°C\n"
            f"  Humidity: {weather_data.get('humidity', 'N/A')}%\n"
            f"  Conditions: {weather_data.get('conditions', 'N/A')}"
        )

# Example usage
if __name__ == "__main__":
    API_ENDPOINT = "https://api.openweathermap.org/data/2.5/weather"
    API_KEY = "your_api_key_here"  # Replace with actual API key

    client = WeatherAPIClient(api_endpoint=API_ENDPOINT, api_key=API_KEY)
    weather_data = client.get_weather_data(location="London")
    if weather_data:
        print(client.format_weather_output(weather_data))
